INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cc1f0e51-229d-4fc5-b4a8-7b65d5daeb31',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow Experiment Tracking — Logging, Comparing, and Querying Runs Like a Pro$escape$,
  $escape$MLflow's tracking server organizes work into experiments, each containing runs. Every run captures params (hyperparameters), metrics (time-series scalars), and artifacts (files, models). Use `mlflow.start_run()` as a context manager — it auto-closes and handles nested runs via the `nested=True` flag.

Log params once per run with `mlflow.log_param()` or bulk via `mlflow.log_params()`. Metrics support step-indexed logging — `mlflow.log_metric('val_loss', loss, step=epoch)` — enabling loss curves in the UI. Artifacts go to the configured store via `mlflow.log_artifact('confusion_matrix.png')` or entire directories with `mlflow.log_artifacts('./outputs/')`.

To compare runs programmatically, use `mlflow.search_runs(experiment_names=['my_exp'], filter_string='metrics.val_accuracy > 0.90', order_by=['metrics.val_accuracy DESC'])` — it returns a pandas DataFrame. Pin your best run as the experiment's champion by tagging it: `mlflow.set_tag('champion', 'true')`. Use `mlflow.get_run(run_id)` to retrieve full metadata, including system tags like `mlflow.source.git.commit` for reproducibility.$escape$,
  $escape$import mlflow

mlflow.set_experiment("transformer-finetune")

with mlflow.start_run(run_name="bert-base-lr3e-5") as run:
    mlflow.log_params({"lr": 3e-5, "epochs": 10, "batch_size": 32})

    for epoch in range(10):
        train_loss, val_acc = train_one_epoch(epoch)
        mlflow.log_metric("train_loss", train_loss, step=epoch)
        mlflow.log_metric("val_accuracy", val_acc, step=epoch)

    mlflow.log_artifact("./outputs/confusion_matrix.png")
    mlflow.set_tag("champion", "true")
    print(f"Run ID: {run.info.run_id}")

best_runs = mlflow.search_runs(
    experiment_names=["transformer-finetune"],
    filter_string="metrics.val_accuracy > 0.92",
    order_by=["metrics.val_accuracy DESC"]
)$escape$,
