INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8e0b00b4-8f5b-4d6e-a32a-dc3644bb350e',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow + DVC — Pinning Data Versions to Experiment Runs for True Reproducibility$escape$,
  $escape$DVC and MLflow solve adjacent problems — DVC owns data and pipeline reproducibility while MLflow owns experiment tracking. Tying them together gives you end-to-end reproducibility: pinned data versions correlated to exact MLflow runs.

Define your pipeline in `dvc.yaml` with explicit `deps` and `outs` so `dvc repro` knows what to rebuild. Inside each stage script, open an `mlflow.start_run()` block and log the `.dvc` pointer files via `mlflow.log_artifact("data/train.csv.dvc")`. This embeds the exact DVC content hash into the MLflow run — anyone can later `dvc checkout` that version from the configured remote (S3, GCS, Azure Blob) and reproduce the run exactly.

Use `mlflow.set_tag("dvc.git_commit", git_sha)` to link the git commit that locks the `.dvc` file state. Configure your DVC remote and MLflow tracking server together so your team can both reproduce data and audit runs from a single source of truth. When `mlflow.get_artifact_uri()` and `dvc remote list` point at the same storage account, you eliminate the "works on my machine" problem at both the data and metrics layer.$escape$,
  $escape$import subprocess
import mlflow

# dvc.yaml stage calls this script; data/train.csv is a DVC-tracked dep
with mlflow.start_run(run_name="train_stage") as run:
    git_sha = subprocess.check_output(["git", "rev-parse", "HEAD"]).decode().strip()
    mlflow.set_tag("dvc.git_commit", git_sha)

    # .dvc pointer file contains the content hash — log it as a run artifact
    mlflow.log_artifact("data/train.csv.dvc")

    acc = train_and_evaluate("data/train.csv")
    mlflow.log_metric("accuracy", acc)

    # Persist run ID so downstream dvc stages can reference it
    with open("mlflow_run_id.txt", "w") as f:
        f.write(run.info.run_id)$escape$,
  $escape$python$escape$,
