INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b11d2f42-2d27-4b70-b9a0-151e99eb01d3',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow + TensorRT — Log Optimized Engines and Track the Latency-Accuracy Tradeoff$escape$,
  $escape$When converting a PyTorch model to TensorRT via `torch2trt` or TensorRT's Python API, MLflow becomes the control plane for tracking every optimization decision. Log the precision mode (`fp32`, `fp16`, `int8`), workspace size, and calibration dataset hash as `mlflow.log_params()`. Use `mlflow.log_metrics()` to capture engine build time, inference latency (p50/p99), and accuracy delta against your FP32 baseline — all in the same run so the tradeoff is visible in one MLflow UI row.

For the engine artifact itself, use `mlflow.log_artifact('model.trt')` alongside the original ONNX file so you can reproduce the build. Tag runs with `mlflow.set_tag('precision', 'int8')` to filter in the Experiments view. When INT8 calibration degrades accuracy beyond your threshold, MLflow's run comparison lets you bisect exactly which layer-wise precision override caused the regression. Register the validated engine under `mlflow.register_model()` with a `trt_sm` tag encoding the target GPU's compute capability — engines are not portable across SM versions.$escape$,
  $escape$import mlflow
import tensorrt as trt

with mlflow.start_run(run_name="resnet50-int8-trt"):
    mlflow.log_params({
        "precision": "int8",
        "workspace_gb": 4,
        "calibration_batches": 100,
        "target_sm": "8.9"
    })

    # ... build TensorRT engine ...
    latency_ms = benchmark_engine(engine, iterations=500)
    accuracy = eval_engine(engine, val_loader)

    mlflow.log_metrics({"p99_latency_ms": latency_ms, "top1_accuracy": accuracy})
    mlflow.log_artifact("resnet50_int8.trt")
    mlflow.log_artifact("resnet50.onnx")
    mlflow.set_tag("trt_sm", "8.9")

    if accuracy >= 0.74:  # FP32 baseline: 0.756
        mlflow.register_model(f"runs:/{mlflow.active_run().info.run_id}/resnet50_int8.trt", "resnet50-trt-int8")$escape$,
  $escape$python$escape$,
