INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0e5a689e-3071-4821-92bf-492cba23769a',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow + Ray — Distributed Training, HPO, and Serving in One Pipeline$escape$,
  $escape$Ray integrates directly with MLflow at every stage of the ML lifecycle. For distributed training, wrap your training function with `ray.remote` and log metrics via `mlflow.log_metric()` inside each worker — MLflow's run context propagates correctly when you pass the `run_id` explicitly to remote tasks. For hyperparameter optimization, Ray Tune's `MLflowLoggerCallback` auto-logs each trial as a nested MLflow run under a parent experiment, giving you full parameter and metric history without manual instrumentation. Set `MLFLOW_EXPERIMENT_NAME` in the Tune config and every trial appears as a child run. For serving, Ray Serve deployments can load models directly via `mlflow.pyfunc.load_model(model_uri)` using the `runs:/` or `models:/` URI scheme, letting you pull the champion model from the Model Registry at deployment time. Combine this with `mlflow.register_model()` post-training and you get a clean promote-to-serve workflow: train → register → serve, all tracked in one MLflow experiment with full lineage from hyperparameter search to production endpoint.$escape$,
  $escape$import mlflow
import ray
from ray import tune
from ray.air.integrations.mlflow import MLflowLoggerCallback

mlflow.set_experiment("ray-hpo-experiment")

def train_fn(config):
    with mlflow.start_run(nested=True):
        model = train_model(config["lr"], config["depth"])
        mlflow.log_metrics({"val_accuracy": evaluate(model)})
        mlflow.sklearn.log_model(model, "model")

tuner = tune.Tuner(
    train_fn,
    param_space={"lr": tune.loguniform(1e-4, 1e-1), "depth": tune.randint(3, 10)},
    run_config=ray.air.RunConfig(
        callbacks=[MLflowLoggerCallback(experiment_name="ray-hpo-experiment")]
    ),
)
results = tuner.fit()
best = results.get_best_result(metric="val_accuracy", mode="max")
mlflow.register_model(f"runs:/{best.metrics['mlflow_run_id']}/model", "champion-model")$escape$,
  $escape$python$escape$,
