INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6d75a28d-69c2-4812-b8fc-5881cb953851',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow Feature Store — Bridging Offline Training and Online Inference$escape$,
  $escape$MLflow's Feature Store separates feature computation from model training, solving the training-serving skew problem. You define feature tables once, write them with `FeatureStoreClient.write_table()`, and reuse them across experiments without recomputing.

The offline store backs training: `client.create_training_set()` performs a point-in-time join between your entity DataFrame and feature tables, returning a `TrainingSet`. The online store backs inference: when you call `client.log_model(..., training_set=training_set)`, MLflow embeds `FeatureLookup` metadata into the model artifact. At serving time, the model accepts only primary keys — MLflow retrieves features from the configured online store (Databricks Online Store, DynamoDB, etc.) automatically.

This means your inference payload never needs to recompute `user_avg_session_duration` — the serving layer fetches it. The `FeatureLookup` spec ties a `table_name`, `feature_names`, and `lookup_key` together, making the lineage auditable via `client.get_feature_table()`. Critically, feature freshness (batch vs. streaming writes) is decoupled from model versioning — update features without redeploying.$escape$,
  $escape$from databricks.feature_store import FeatureStoreClient, FeatureLookup

fs = FeatureStoreClient()

# Define what features to pull and on which key
feature_lookups = [
    FeatureLookup(
        table_name="ml.user_features",
        feature_names=["avg_session_duration", "click_through_rate"],
        lookup_key="user_id",
    )
]

# Point-in-time join for training
training_set = fs.create_training_set(
    df=labels_df,  # DataFrame with user_id + label
    feature_lookups=feature_lookups,
    label="converted",
)

# Log model — embeds FeatureLookup metadata for online serving
with mlflow.start_run():
    fs.log_model(
        model=clf,
        artifact_path="model",
        flavor=mlflow.sklearn,
        training_set=training_set,
        registered_model_name="user_conversion_model",
    )$escape$,
  $escape$python$escape$,
