INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3eab9b6b-45ec-4418-9293-97b34731508c',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow — Logging and Comparing Quantized Models with the Model Registry$escape$,
  $escape$Quantization and pruning shrink model size and accelerate inference, but MLflow gives you the tooling to make these trade-offs visible and reproducible. When converting a PyTorch model to int8 via `torch.quantization.quantize_dynamic` or exporting an ONNX model with fp16 weights, log the compressed artifact directly with `mlflow.pytorch.log_model` or `mlflow.onnx.log_model`, tagging the run with `mlflow.set_tag("quantization", "int8")`. Use `mlflow.log_metrics` to record accuracy delta, latency (ms), and model size (MB) alongside your baseline run — this lets you compare full-precision vs. quantized runs side-by-side in the MLflow UI under the same experiment. For structured pruning, log sparsity percentage as a param: `mlflow.log_param("sparsity", 0.4)`. Promote the quantized model to the Model Registry only when its accuracy degradation stays within your threshold, using `mlflow.register_model` with an alias like `quantized-prod`. The `MlflowClient.search_model_versions` API lets you query by tag to audit which registry versions are compressed variants vs. full-precision baselines.$escape$,
  $escape$import mlflow
import mlflow.pytorch
import torch

with mlflow.start_run(run_name="resnet50-int8") as run:
    model = torch.quantization.quantize_dynamic(
        base_model, {torch.nn.Linear}, dtype=torch.qint8
    )
    mlflow.set_tag("quantization", "int8")
    mlflow.log_param("dtype", "qint8")
    mlflow.log_metric("accuracy", 0.923)
    mlflow.log_metric("model_size_mb", 11.4)
    mlflow.log_metric("latency_ms", 18.2)
    mlflow.pytorch.log_model(model, artifact_path="model")
    model_uri = f"runs:/{run.info.run_id}/model"
    mlflow.register_model(model_uri, "ResNet50", tags={"variant": "int8-quantized"})$escape$,
  $escape$python$escape$,
