INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5fc3bf8f-c909-47ca-bf1a-03277a842ced',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow — Cut GPU Training Costs with Spot Instances and Run Recovery$escape$,
  $escape$Spot instances can slash GPU training costs by 60–90%, but preemptions will kill your runs. MLflow's run resumption pattern makes this tractable. Tag every run with `mlflow.set_tag('spot_instance', 'true')` and log checkpoints as artifacts at fixed epoch intervals using `mlflow.log_artifact(checkpoint_path)`. When a spot instance is reclaimed, your training script checks for the latest checkpoint artifact via `mlflow.artifacts.download_artifacts(run_id=run_id, artifact_path='checkpoints/latest.pt')` and resumes from that epoch. Use `mlflow.start_run(run_id=existing_run_id)` to continue logging metrics into the same run rather than creating a new one — this keeps your loss curves unbroken in the UI. For multi-node GPU clusters, set `MLFLOW_TRACKING_URI` consistently across all nodes and use `mlflow.log_metric(step=global_step)` with explicit step values so metrics from resumed runs align correctly on the timeline. Pair this with MLflow's `mlflow.pytorch.autolog(checkpoint=True)` to auto-save model state every N steps without manual checkpoint code.$escape$,
  $escape$import mlflow
import mlflow.pytorch

mlflow.pytorch.autolog(checkpoint=True, checkpoint_save_best_only=False)

existing_run_id = os.getenv("MLFLOW_RUN_ID")  # set on spot relaunch

with mlflow.start_run(run_id=existing_run_id) as run:
    mlflow.set_tag("spot_instance", "true")
    mlflow.set_tag("instance_type", os.getenv("EC2_INSTANCE_TYPE", "unknown"))

    checkpoint_path = None
    if existing_run_id:
        checkpoint_path = mlflow.artifacts.download_artifacts(
            run_id=existing_run_id, artifact_path="checkpoints/latest.pt"
        )

    model, start_epoch = load_or_init(checkpoint_path)

    for epoch in range(start_epoch, MAX_EPOCHS):
        loss = train_epoch(model, epoch)
        mlflow.log_metric("train_loss", loss, step=epoch)$escape$,
  $escape$python$escape$,
